import json

items = $input.all()
rows = []
if items:
    rows = items[0].get("json", {}).get("rows", [])
    if not rows:
        rows = [item["json"] for item in items]

DAILY_BUDGET_CENTS = 2000  # $20.00
WARNING_THRESHOLD = 0.8

by_layer = {}
total_cents = 0

for row in rows:
    layer = row.get("layer_id", "unknown")
    model = row.get("model_used", "unknown")
    cents = int(row.get("total_cents", 0))
    runs = int(row.get("total_runs", 0))
    total_cents += cents

    if layer not in by_layer:
        by_layer[layer] = {"models": {}, "layer_total_cents": 0}
    by_layer[layer]["models"][model] = {"cost_cents": cents, "runs": runs}
    by_layer[layer]["layer_total_cents"] += cents

budget_percent = round((total_cents / DAILY_BUDGET_CENTS) * 100, 2)

if total_cents >= DAILY_BUDGET_CENTS:
    status = "critical"
elif total_cents >= int(DAILY_BUDGET_CENTS * WARNING_THRESHOLD):
    status = "warning"
else:
    status = "normal"

return [{
    "json": {
        "total_cost_cents": total_cents,
        "total_cost_dollars": round(total_cents / 100, 4),
        "daily_budget_cents": DAILY_BUDGET_CENTS,
        "daily_budget_dollars": DAILY_BUDGET_CENTS / 100,
        "budget_percent": budget_percent,
        "by_layer": by_layer,
        "status": status,
        "is_warning": status == "warning",
        "is_critical": status == "critical"
    }
}]

